#include <stdio.h>
#include <string.h>

struct Student {
    char name[30];
    int roll;
    float gpa;
};

int main() {
    struct Student s1;
    strcpy(s1.name, "করিম");
    s1.roll = 101;
    s1.gpa = 3.85;

    printf("নাম: %s, রোল: %d, GPA: %.2f\n", s1.name, s1.roll, s1.gpa);

    // ঘোষণার সময়েই মান দেওয়া
    struct Student s2 = {"রহিম", 102, 3.60};
    printf("%s\n", s2.name);

    return 0;
}

struct Student s1 = {"নাফিস", 103, 3.9};
struct Student *ptr = &s1;

printf("%s\n", ptr->name); // অ্যারো অপারেটর দিয়ে অ্যাক্সেস

